// Query helpers
export const getPublicationsByTag = (tag: PublicationTag): Publication[] =>
  publications.filter(p => p.tags.includes(tag))

export const getPublicationsByKind = (kind: Publication['kind']): Publication[] =>
  publications.filter(p => p.kind === kind)

export const getFirstAuthorPublications = (): Publication[] =>
  publications.filter(p => p.isFirstAuthor)

export const getPublicationsByYear = (year: number): Publication[] =>
  publications.filter(p => p.year === year)
